#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start, end, weight;
} Interval;

int compare(const void *a, const void *b) {
    return ((Interval*)a)->end - ((Interval*)b)->end;
}

int binarySearch(int *finishTimes, int n, int target) {
    int low = 1, high = n, result = 0;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (finishTimes[mid] <= target) {
            result = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    return result;
}

void weightedIntervalScheduling(Interval *intervals, int n) {
    // Sort by finish time
    qsort(intervals, n, sizeof(Interval), compare);

    // Create finish times array (1-indexed)
    int *finishTimes = (int*)malloc((n + 1) * sizeof(int));
    for (int i = 1; i <= n; i++)
        finishTimes[i] = intervals[i - 1].end;

    // Compute p(i)
    int *p = (int*)malloc((n + 1) * sizeof(int));
    for (int i = 1; i <= n; i++)
        p[i] = binarySearch(finishTimes, n, intervals[i - 1].start);

    // DP computation
    int *dp = (int*)malloc((n + 1) * sizeof(int));
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        int include = intervals[i - 1].weight + dp[p[i]];
        dp[i] = (dp[i - 1] > include) ? dp[i - 1] : include;
    }

    printf("Maximum Weight: %d\n", dp[n]);

    // Reconstruct solution
    printf("Selected Intervals: ");
    int i = n;
    while (i > 0) {
        int include = intervals[i - 1].weight + dp[p[i]];
        if (include > dp[i - 1]) {
            printf("(%d,%d,%d) ", intervals[i-1].start, 
                   intervals[i-1].end, intervals[i-1].weight);
            i = p[i];
        } else {
            i--;
        }
    }
    printf("\n");

    free(finishTimes);
    free(p);
    free(dp);
}

int main() {
    Interval intervals[] = {{0,3,5}, {2,5,6}, {4,6,4}, {5,7,2}, {6,8,8}};
    int n = sizeof(intervals) / sizeof(intervals[0]);
    weightedIntervalScheduling(intervals, n);
    return 0;
}
